/// <summary>
/// UI Builder class for customizing the user interface of the Unsold Journal Check Post process in the ETGSPAIN model.
/// </summary>
class ETGSPAINUnsoldJournalCheckPostUIBuilder extends SysOperationAutomaticUIBuilder
{
    DialogField         dfETGSPAINUnsoldJournalId;

}

Method.Source:
/// <summary>
/// This method is executed after the UI has been fully built.
/// It customizes the dialog by disabling the Unsold Journal field if conditions are met.
/// </summary>
public void postRun()
{
    super();

    ETGSPAINUnsoldJournalCheckPostContract contract = this.dataContractObject() as ETGSPAINUnsoldJournalCheckPostContract;

    if (contract.parmArgs().record() && contract.parmETGSPAINUnsoldJournalId())
    {
        dfETGSPAINUnsoldJournalId = this.bindInfo().getDialogField(contract, methodStr(ETGSPAINUnsoldJournalCheckPostContract, parmETGSPAINUnsoldJournalId));
        dfETGSPAINUnsoldJournalId.enabled(false);
    }
}
